	@Test
	void rowPreservingAccessPathAlternativesRetainMemoChildAndDeferWrapperCost() {
		RowPreservingAccessPathStatistics statistics = new RowPreservingAccessPathStatistics();
		Extension wrapper = new Extension(
				new StatementPattern(new Var("comp"), new Var("namePredicate"), new Var("optName")),
				new ExtensionElem(new Var("optName"), "optCompName"));
		OptimizationGoal goal = OptimizationGoal.root()
				.withRequiredProperties(PhysicalProperties.builder().boundVars(Set.of("comp")).build());
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		int groupId = memo.intern(wrapper);
		MemoExpr logical = memo.group(groupId).expressions().getFirst();
		CascadesRule rule = LmdbCascadesRuleProvider.rules(statistics)
				.applicableRules(logical, goal, memo)
				.stream()
				.filter(candidate -> "lmdb-row-preserving-subplan-access-path".equals(candidate.id()))
				.findFirst()
				.orElseThrow();

		List<RuleApplication> applications = rule.apply(logical, goal,
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));

		assertEquals(2, applications.size(), "The fixture must exercise base and requested-bound access paths");
		for (RuleApplication application : applications) {
			MemoExpr physical = memo.addPhysicalAlternative(application.targetGroupId(), application.alternative(),
					application.deliveredProperties(), application.inputRequirements(), application.metadata(),
					application.kind(), application.localCost(), application.proofs(), application.estimate(),
					application.opaque())
					.orElseThrow();

			assertAll(application.metadata(),
					() -> assertFalse(application.opaque(),
							"A row-preserving wrapper must leave its child available to memo planning"),
					() -> assertEquals(logical.inputGroupIds(), physical.inputGroupIds(),
							"The installed wrapper must retain its statement-pattern memo child"),
					() -> assertEquals(1, physical.inputGroupIds().size()),
					() -> assertEquals(application.inputRequirements(), physical.inputRequirements(),
							"The installed wrapper must preserve its executable child contract"),
					() -> assertEquals(application.deliveredProperties().accessPath(),
							application.inputRequirements().getFirst().accessPath(),
							"The child requirement must select the access path advertised by the wrapper"),
					() -> assertEquals(CostVector.ZERO, application.localCost(),
							"The wrapper must not declare its child's complete access-path work as local work"),
					() -> assertTrue(application.estimate().workRows() > 0.0d,
							"Deferring explicit local cost must preserve the access-path estimate evidence"));
		}
	}

	@Test
	void innerJoinUsesSingleGenericSelectedPrefixImplementation() {
		WholeJoinBoundLookupStatistics statistics = new WholeJoinBoundLookupStatistics();
		StatementPattern left = new StatementPattern(
				new Var("root", VF.createIRI("urn:root")),
				new Var("edge", VF.createIRI("urn:edge")),
				new Var("entity"));
		StatementPattern right = new StatementPattern(
				new Var("entity"),
				new Var("property", VF.createIRI("urn:property")),
				new Var("value"));
		Join join = new Join(left, right);
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		int groupId = memo.intern(join);
		MemoExpr logical = memo.group(groupId).expressions().getFirst();
		List<CascadesRule> applicable = LmdbCascadesRuleProvider.rules(statistics)
				.applicableRules(logical, OptimizationGoal.root(), memo);
		List<String> selectedPrefixIteratorRules = applicable.stream()
				.map(CascadesRule::id)
				.filter(Set.of("generic-physical-implementation", "lmdb-inner-join-bound-lookup")::contains)
				.toList();
		CascadesRule generic = applicable.stream()
				.filter(rule -> "generic-physical-implementation".equals(rule.id()))
				.findFirst()
				.orElseThrow();
		RuleApplication application = generic.apply(logical, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null)).getFirst();

		assertAll(
				() -> assertEquals(List.of("generic-physical-implementation"), selectedPrefixIteratorRules,
						"A specialized rule must not duplicate the canonical parameterized iterator join"),
				() -> assertFalse(application.opaque(),
						"The physical join must retain independently selectable memo children"),
				() -> assertEquals(CostVector.ZERO, application.localCost(),
						"A structural join rule must not freeze a whole-subtree estimate into local operator cost"),
				() -> assertEquals(0, statistics.fullJoinEstimateCalls,
						"A capability rule must not recursively estimate the whole join before memo children are selected"),
				() -> assertEquals(PhysicalProperties.InputConsumption.SELECTED_PREFIX,
						application.inputRequirements().get(1).inputConsumption(),
						"The right input must be costed under the optimizer-selected left prefix"));
	}

	@Test
	void guaranteeOptionsEnterMemoAsIndependentLogicalAlternatives() {
		SemanticRewriteCostingStatistics statistics = new SemanticRewriteCostingStatistics();
		IRI weightPredicate = VF.createIRI("urn:weight");
		TupleExpr input = new Join(
				new StatementPattern(new Var("node"), new Var("typePredicate"), new Var("type")),
				new StatementPattern(new Var("node"), new Var("weightPredicate", weightPredicate), new Var("w")));
		Filter filter = new Filter(input, listMember("w", "urn:w1", "urn:w2", "urn:w3", "urn:w4"));

		List<RuleApplication> applications = ruleApplications(filter, statistics, OptimizationGoal.root(),
				"lmdb-guarantee-options");

		assertFalse(applications.isEmpty(), applications::toString);
		assertTrue(applications.stream().allMatch(application -> application.kind() == RuleKind.TRANSFORMATION),
				applications::toString);
		assertTrue(applications.stream().noneMatch(RuleApplication::opaque), applications::toString);
		assertEquals(applications.size(), applications.stream()
				.map(application -> application.alternative()
						.getStringMetricPlanned("optimizer.guaranteeOption"))
				.distinct()
				.count(), applications::toString);
		for (RuleApplication application : applications) {
			int[] markedNodes = { 0 };
			application.alternative().visit(new AbstractQueryModelVisitor<RuntimeException>() {
				@Override
				public void meet(Filter node) {
					assertEquals("true", node.getStringMetricPlanned("optimizer.guaranteeAlternative"),
							"Nested filters must not reopen guarantee-option expansion");
					markedNodes[0]++;
					super.meet(node);
				}

				@Override
				public void meet(Join node) {
					assertEquals("true", node.getStringMetricPlanned("optimizer.guaranteeAlternative"),
							"Nested joins must not reopen guarantee-option expansion");
					markedNodes[0]++;
					super.meet(node);
				}
			});
			assertTrue(markedNodes[0] > 1, "The regression must exercise a nested guarantee alternative");
		}

		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		int groupId = memo.intern(filter);
		LmdbGuaranteeOptionRule rule = new LmdbGuaranteeOptionRule(statistics);
		Join originalJoin = (Join) filter.getArg();
		Filter rematerialized = new Filter(
				new Join(originalJoin.getRightArg().clone(), originalJoin.getLeftArg().clone()),
				filter.getCondition().clone());
		MemoExpr historicalAlternative = memo
				.addLogicalAlternative(groupId, rematerialized, applications.getFirst().proofs())
				.orElseThrow();
		assertFalse(rule.matches(historicalAlternative, OptimizationGoal.root(), memo),
				"A later rewrite that drops local metrics must not reopen the same guarantee alternative");
	}

	@Test
	void guaranteeOptionsAnalyzeEachImmutableJoinExpressionOnce() {
		SemanticRewriteCostingStatistics statistics = new SemanticRewriteCostingStatistics();
		IRI weightPredicate = VF.createIRI("urn:weight");
		TupleExpr input = new Join(
				new StatementPattern(new Var("node"), new Var("typePredicate"), new Var("type")),
				new Join(
						new StatementPattern(new Var("node"), new Var("edgePredicate"), new Var("edge")),
						new StatementPattern(new Var("edge"), new Var("weightPredicate", weightPredicate),
								new Var("w"))));
		Filter filter = new Filter(input, listMember("w", "urn:w1", "urn:w2", "urn:w3", "urn:w4"));
		Map<GuaranteeInvocationKey, Integer> emittingInvocations = new HashMap<>();
		CascadesRule guaranteeRule = new LmdbGuaranteeOptionRule(statistics);
		RuleRegistry registry = RuleRegistry.builder()
				.add(new CountingEmittingRule(guaranteeRule, emittingInvocations))
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();

		CascadesPlan plan = new CascadesPlanner(CascadesCostModel.from(statistics), registry,
				CascadesTelemetry.NO_OP).optimize(filter, OptimizationGoal.root());

		assertTrue(emittingInvocations.size() > 1,
				"Unified join search must expose more than one immutable expression to the guarantee rule");
		assertTrue(emittingInvocations.values().stream().allMatch(count -> count == 1),
				() -> "Proof and child revisions must not replay an already analyzed expression and goal: invocations="
						+ emittingInvocations + ", diagnostics=" + plan.diagnostics());
	}

