	private static void restoreMode(String previousMode) {
		if (previousMode == null) {
			System.clearProperty(LmdbCascadesOptimizer.MODE_PROPERTY);
		} else {
			System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, previousMode);
		}
	}

	private static RuleApplication ruleApplication(TupleExpr tupleExpr, EvaluationStatistics statistics,
			OptimizationGoal goal, String ruleId) {
		return ruleApplications(tupleExpr, statistics, goal, ruleId).getFirst();
	}

	private static List<RuleApplication> ruleApplications(TupleExpr tupleExpr, EvaluationStatistics statistics,
			OptimizationGoal goal, String ruleId) {
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		RuleRegistry registry = LmdbCascadesRuleProvider.rules(statistics);
		int groupId = memo.intern(tupleExpr);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		CascadesRule rule = registry.applicableRules(expression, goal, memo)
				.stream()
				.filter(candidate -> candidate.id().equals(ruleId))
				.findFirst()
				.orElseThrow(() -> new AssertionError("Missing rule " + ruleId));
		return rule.apply(expression, goal,
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));
	}

	private static TupleExpr thresholdPathIsland() {
		IRI type = VF.createIRI("http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
		IRI aasClass = VF.createIRI("https://admin-shell.io/aas/3/AssetAdministrationShell");
		IRI assetInformation = VF.createIRI("https://admin-shell.io/aas/3/assetInformation");
		IRI specificAssetId = VF.createIRI("https://admin-shell.io/aas/3/specificAssetId");
		IRI submodel = VF.createIRI("https://admin-shell.io/aas/3/submodel");
		IRI submodelElement = VF.createIRI("https://admin-shell.io/aas/3/submodelElement");
		IRI value = VF.createIRI("https://admin-shell.io/aas/3/value");
		IRI idShort = VF.createIRI("https://admin-shell.io/aas/3/idShort");

		TupleExpr left = new Join(
				new StatementPattern(new Var("aas"), new Var("type", type), new Var("aasClass", aasClass)),
				new StatementPattern(new Var("assetInfo"), new Var("value", value),
						new Var("driveUnit", VF.createLiteral("DriveUnit"))));
		left = new Join(left,
				new Join(
						new StatementPattern(new Var("aas"), new Var("assetInformation", assetInformation),
								new Var("assetInfoRoot")),
						new StatementPattern(new Var("assetInfoRoot"), new Var("specificAssetId", specificAssetId),
								new Var("assetInfo"))));
		TupleExpr pathBranch = new Join(
				new Join(
						new StatementPattern(new Var("aas"), new Var("submodel", submodel), new Var("submodelNode")),
						new StatementPattern(new Var("submodelNode"), new Var("submodelElement", submodelElement),
								new Var("element"))),
				new ArbitraryLengthPath(new Var("element"),
						new StatementPattern(new Var("pathS"), new Var("valueStep", value), new Var("pathO")),
						new Var("p1"), 0L));
		TupleExpr propertyBranch = new Join(
				new StatementPattern(new Var("p1"), new Var("idShort", idShort),
						new Var("ratedPower", VF.createLiteral("ratedPower"))),
				new Filter(
						new StatementPattern(new Var("p1"), new Var("value", value), new Var("v1")),
						new Compare(new Var("v1"),
								new ValueConstant(VF.createLiteral("15.0", XMLSchema.DECIMAL)),
								Compare.CompareOp.GT)));
		return new Join(new Join(left, pathBranch), propertyBranch);
	}

	private static ListMemberOperator listMember(String variableName, String... iriValues) {
		ListMemberOperator operator = new ListMemberOperator();
		operator.addArgument(new Var(variableName));
		for (String iriValue : iriValues) {
			operator.addArgument(new ValueConstant(VF.createIRI(iriValue)));
		}
		return operator;
	}

	private record JoinOrderCall(Set<String> initiallyBoundVars, List<Set<String>> argBindingNames) {
		private boolean minusRightJoinBoundToPerson() {
			return initiallyBoundVars.contains("person")
					&& argBindingNames.contains(Set.of("person", "minusPredicate", "event"))
					&& argBindingNames.contains(Set.of("event", "eventPredicate", "date"));
		}
	}

	private static List<StatementPattern> unanchoredBoundLookupTypeGuards(TupleExpr tupleExpr) {
		List<StatementPattern> result = new ArrayList<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				if (isRelationshipTypeGuard(node)
						&& "rel".equals(node.getStringMetricPlanned("testBoundContext"))
						&& !isBoundByLeftAncestor(node, "rel")) {
					result.add(node);
				}
			}
		});
		return result;
	}

	private static boolean isRelationshipTypeGuard(StatementPattern pattern) {
		return pattern.getSubjectVar() != null
				&& "rel".equals(pattern.getSubjectVar().getName())
				&& pattern.getPredicateVar() != null
				&& "type".equals(pattern.getPredicateVar().getName())
				&& pattern.getObjectVar() != null
				&& "relationshipType".equals(pattern.getObjectVar().getName());
	}

	private static boolean isBoundByLeftAncestor(QueryModelNode node, String bindingName) {
		QueryModelNode current = node;
		QueryModelNode parent = current.getParentNode();
		while (parent != null) {
			if (parent instanceof Join join && containsNode(join.getRightArg(), current)
					&& join.getLeftArg().getBindingNames().contains(bindingName)) {
				return true;
			}
			current = parent;
			parent = parent.getParentNode();
		}
		return false;
	}

	private static boolean containsNode(QueryModelNode root, QueryModelNode needle) {
		if (root == needle) {
			return true;
		}
		List<Boolean> found = new ArrayList<>(List.of(false));
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meetNode(QueryModelNode node) {
				if (node == needle) {
					found.set(0, true);
				}
				if (!found.get(0)) {
					super.meetNode(node);
				}
			}
		});
		return found.get(0);
	}

	private static StatementPattern statementPatternWithPredicateName(TupleExpr tupleExpr, String predicateName) {
		List<StatementPattern> matches = new ArrayList<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				if (node.getPredicateVar() != null && predicateName.equals(node.getPredicateVar()
						.getName())) {
					matches.add(node);
				}
			}
		});
		assertEquals(1, matches.size(), () -> tupleExpr.toString());
		return matches.getFirst();
	}

