			Map<String, Double> metrics = Map.of(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, workRows);
			return Optional.of(new JoinOrderPlan(args, 10.0d, workRows, List.of(), Map.of(), metrics, List.of()));
