	private record CountingEmittingRule(CascadesRule delegate,
			Map<GuaranteeInvocationKey, Integer> invocations) implements CascadesRule {

		@Override
		public String id() {
			return delegate.id();
		}

		@Override
		public RuleKind kind() {
			return delegate.kind();
		}

		@Override
		public RuleDescriptor descriptor() {
			return delegate.descriptor();
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return delegate.matches(expression, goal, memo);
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return delegate.promise(expression, goal, memo);
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			List<RuleApplication> applications = delegate.apply(expression, goal, context);
			if (!applications.isEmpty()) {
				invocations.merge(new GuaranteeInvocationKey(expression.id(), goal), 1, Integer::sum);
			}
			return applications;
		}
	}

	private record GuaranteeInvocationKey(int expressionId, OptimizationGoal goal) {
	}

