	private static final class WholeJoinBoundLookupStatistics extends EvaluationStatistics
			implements JoinFactorCostModel {
		private int fullJoinEstimateCalls;

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			return estimate(factor);
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, CostContext context) {
			return estimate(factor);
		}

		private Optional<FactorCostEstimate> estimate(TupleExpr factor) {
			if (!(factor instanceof Join)) {
				return Optional.empty();
			}
			fullJoinEstimateCalls++;
			double inflatedWholeJoinRows = 3_315_000_000.0d;
			return Optional.of(new FactorCostEstimate(inflatedWholeJoinRows, inflatedWholeJoinRows,
					Map.of(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, "lmdb-inner-bound-lookup"),
					Map.of(
							"plannedInnerJoinOutputRows", inflatedWholeJoinRows,
							"plannedInnerJoinRightRows", inflatedWholeJoinRows,
							"plannedInnerJoinRightWorkRows", inflatedWholeJoinRows)));
		}
	}
